#!/usr/bin/env python3
"""
Writes a brand new translations.js from scratch and fixes App.jsx.
No patching - just replaces the whole file cleanly.
"""
import re, shutil, os

# ── Fix App.jsx first: remove any broken inline T insertions ─────
APP = "src/App.jsx"
with open(APP, "r", encoding="utf-8") as f:
    app = f.read()

# Find and remove anything between about:"About" (or similar) and },
# that looks like broken key insertions (lines starting with known bad patterns)
# Strategy: find the line with the error and clean it
lines = app.split("\n")
fixed_lines = []
for line in lines:
    # Remove lines that are just broken key dumps not inside a proper block
    if re.match(r'^,whyMatched:', line) or re.match(r'^,aboutDest:', line):
        continue  # skip broken insertion lines
    fixed_lines.append(line)
app = "\n".join(fixed_lines)

# Also fix the truncated string issue - find pattern like "Neni to on,whyMatched
app = re.sub(r'"Neni to on,', '"Neni to ono?",___REMOVE___, notQuiteRight_placeholder', app)

with open(APP, "w", encoding="utf-8") as f:
    f.write(app)

print("✅ App.jsx cleaned")

